mapper.select:
/* TripleHistMgmtMapper.getTripleHistList */
SELECT A.KT_INTERNET_ID ,A.CONTRACT_NUM ,B.SUB_LINK_NAME ,B.SUBSCRIBER_NO ,SUBSTR(CRYPTO_AES256.DEC_AES(NVL(B.USER_SSN, ' ')), 1,6) AS USER_SSN ,C.LST_RATE_NM ,(SELECT DISTINCT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.RATE_CD) AS RATE_NM ,A.RATE_CD ,(SELECT DISTINCT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.ADDITION_CD) AS ADDITION_NM ,A.ADDITION_CD ,B.LST_COM_ACTV_DATE ,A.INSTALL_DD ,A.APP_ROUTE ,A.PRCS_MDL_IND ,A.CRET_DD ,A.CRET_ID ,A.AMD_ID ,TO_CHAR(A.CRET_DT,'YYYY-MM-DD HH24:MI:SS') AS CRET_DT ,A.AMD_DT ,DECODE(A.SUCC_YN,'Y','성공','실패') AS SUCC_YN ,A.PROC_YN ,A.PROC_ID AS PROC_ID ,FN_GET_USRNM(A.PROC_ID) AS PROC_NM ,TO_CHAR(A.PROC_DT,'YYYY-MM-DD HH24:MI:SS') AS PROC_DT ,A.REASON_FAIL FROM MCP_TRIPLE_DISCOUNT@DL_MCP A, MSP_JUO_SUB_INFO B, MSP_REQUEST_DTL C WHERE 1=1 AND A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM
AND TO_CHAR(A.CRET_DT,'YYYYMMDD') BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.CONTRACT_NUM = #{searchName}
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND A.KT_INTERNET_ID = #{searchName}
AND B.SUBSCRIBER_NO = #{searchName}
AND (SELECT DISTINCT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.ADDITION_CD) LIKE '%' || #{searchName} || '%'
AND A.APP_ROUTE = #{appRoute}
AND A.SUCC_YN = #{succYn}
AND DECODE(A.PROC_YN,'Y','Y','N') = #{procYn}
ORDER BY A.CRET_DT DESC

/* TripleHistMgmtMapper.getTripleHistListExcel */ SELECT A.KT_INTERNET_ID ,A.CONTRACT_NUM ,B.SUB_LINK_NAME ,B.SUBSCRIBER_NO ,SUBSTR(CRYPTO_AES256.DEC_AES(NVL(B.USER_SSN, ' ')), 1,6) AS USER_SSN ,C.LST_RATE_NM ,(SELECT DISTINCT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.RATE_CD) AS RATE_NM ,A.RATE_CD ,(SELECT DISTINCT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.ADDITION_CD) AS ADDITION_NM ,A.ADDITION_CD ,B.LST_COM_ACTV_DATE ,A.INSTALL_DD ,A.APP_ROUTE ,A.PRCS_MDL_IND ,A.CRET_DD ,A.CRET_ID ,A.AMD_ID ,TO_CHAR(A.CRET_DT,'YYYY-MM-DD HH24:MI:SS') AS CRET_DT ,A.AMD_DT ,DECODE(A.SUCC_YN,'Y','성공','실패') AS SUCC_YN ,A.PROC_YN ,A.PROC_ID AS PROC_ID ,FN_GET_USRNM(A.PROC_ID) AS PROC_NM ,TO_CHAR(A.PROC_DT,'YYYY-MM-DD HH24:MI:SS') AS PROC_DT ,A.REASON_FAIL FROM MCP_TRIPLE_DISCOUNT@DL_MCP A, MSP_JUO_SUB_INFO B, MSP_REQUEST_DTL C WHERE 1=1 AND A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM
AND TO_CHAR(A.CRET_DT,'YYYYMMDD') BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.CONTRACT_NUM = #{searchName}
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND A.KT_INTERNET_ID = #{searchName}
AND B.SUBSCRIBER_NO = #{searchName}
AND (SELECT DISTINCT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.ADDITION_CD) LIKE '%' || #{searchName} || '%'
AND A.APP_ROUTE = #{appRoute}
AND A.SUCC_YN = #{succYn}
AND DECODE(A.PROC_YN,'Y','Y','N') = #{procYn}
ORDER BY A.CRET_DT DESC

SELECT
	COUNT(*)
FROM MCP_TRIPLE_DISCOUNT@DL_MCP
WHERE KT_INTERNET_ID = #{nKtInternetId}
AND CONTRACT_NUM = #{contractNum}

mapper.insert:
/* TripleHistMgmtMapper.insertTripleHist */
INSERT INTO MCP_TRIPLE_DISCOUNT@DL_MCP
(
	CONTRACT_NUM
	,KT_INTERNET_ID
	,RATE_CD
	,ADDITION_CD
	,INSTALL_DD
	,APP_ROUTE
	,CRET_DD
	,CRET_ID
	,CRET_DT
	,RIP
	,SUCC_YN
) VALUES(
	#{contractNum}
	,#{nKtInternetId}
	,#{rateCd}
	,#{additionCd}
	,#{installDd}
	,'고객센터'
	,TO_CHAR(SYSDATE,'YYYYMMDD')
	,#{regId}
	,SYSDATE
	,#{rip}
	,'Y'
)

mapper.update:
UPDATE MCP_TRIPLE_DISCOUNT@DL_MCP
SET
	KT_INTERNET_ID = #{nKtInternetId}
	,INSTALL_DD = #{installDd}
	,AMD_ID = #{rvisnId}
	,AMD_DT = SYSDATE
WHERE CONTRACT_NUM = #{contractNum}
AND KT_INTERNET_ID = #{ktInternetId}

UPDATE MCP_TRIPLE_DISCOUNT@DL_MCP
SET
	PROC_YN = 'Y'
	,PROC_ID = #{regId}
	,PROC_DT = SYSDATE
	,AMD_ID = #{rvisnId}
	,AMD_DT = SYSDATE
WHERE CONTRACT_NUM = #{contractNum}
AND KT_INTERNET_ID = #{ktInternetId}
